package com.taxin60sec.backend.service.impl;
import com.taxin60sec.backend.dto.business.*; import com.taxin60sec.backend.entity.*; import com.taxin60sec.backend.entity.enums.*; import com.taxin60sec.backend.mapper.BusinessProfileMapper; import com.taxin60sec.backend.repository.*; import org.junit.jupiter.api.Test; import java.util.Optional; import static org.junit.jupiter.api.Assertions.*; import static org.mockito.ArgumentMatchers.any; import static org.mockito.Mockito.*;
class BusinessProfileServiceImplTest {
 @Test void createsBusinessForExistingClientAndCa(){BusinessProfileRepository businesses=mock(BusinessProfileRepository.class);ClientProfileRepository clients=mock(ClientProfileRepository.class);UserRepository users=mock(UserRepository.class);BusinessProfileMapper mapper=new BusinessProfileMapper();BusinessProfileServiceImpl service=new BusinessProfileServiceImpl(businesses,clients,users,mapper);ClientProfile client=new ClientProfile();client.setId(10L);User ca=new User();ca.setId(20L);when(clients.findById(10L)).thenReturn(Optional.of(client));when(users.findById(20L)).thenReturn(Optional.of(ca));when(businesses.save(any(BusinessProfile.class))).thenAnswer(i->{BusinessProfile b=i.getArgument(0);b.setId(30L);return b;});BusinessProfileRequest request=new BusinessProfileRequest(10L,"Tax60 Pvt Ltd",BusinessType.PRIVATE_LIMITED,"ABCDE1234F",null,null,null,null,null,BusinessStatus.ACTIVE,20L,"Pune");BusinessProfileResponse response=service.createBusiness(request);assertEquals(30L,response.id());assertEquals(10L,response.clientProfileId());assertEquals(20L,response.assignedCaId());verify(businesses).save(any(BusinessProfile.class));}
}
